import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function optimizePaymentRoute(amount, tokenSymbol) {
  const chains = ["eth-mainnet", "arbitrum-mainnet", "base-mainnet", "matic-mainnet"];
  const gasPrices = await Promise.all(
    chains.map(c => client.BaseService.getGasPrices(c, "eip1559"))
  );
  return chains.map((chain, i) => ({
    chain,
    gasPrice: gasPrices[i].data?.items?.[0]?.gas_price ?? null,
  })).sort((a, b) => (a.gasPrice ?? 0) - (b.gasPrice ?? 0));
}
